"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { Mail, Phone, Lock, AlertCircle, Loader2, Eye, EyeOff } from "lucide-react";

export default function Login() {
    const { login, user, loading: authLoading } = useAuth();
    const router = useRouter();

    const [identifier, setIdentifier] = useState("");
    const [password, setPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);
    const [error, setError] = useState("");
    const [submitting, setSubmitting] = useState(false);

    // If already logged in, redirect to dashboard
    useEffect(() => {
        if (!authLoading && user) {
            router.replace("/");
        }
    }, [authLoading, user, router]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError("");
        setSubmitting(true);

        // small delay so the spinner is visible
        await new Promise((r) => setTimeout(r, 400));

        const result = login(identifier.trim(), password);

        if (result.success) {
            router.push("/");
        } else {
            setError(result.message);
            setSubmitting(false);
        }
    };

    // Show nothing while rehydrating auth
    if (authLoading) return null;
    if (user) return null;

    return (
        <div className="min-h-screen flex">
            {/* Left panel — branding */}
            <div className="hidden lg:flex lg:w-1/2 bg-gradient-to-br from-[#2D5A27] to-[#33cc33] relative overflow-hidden items-center justify-center">
                {/* Decorative circles */}
                <div className="absolute -top-24 -left-24 w-96 h-96 bg-white/5 rounded-full" />
                <div className="absolute -bottom-32 -right-32 w-[500px] h-[500px] bg-white/5 rounded-full" />
                <div className="absolute top-1/3 right-10 w-40 h-40 bg-white/10 rounded-full" />

                <div className="relative z-10 max-w-md px-12 text-white">
                    <img src="/ann-setu-logo.svg" alt="Ann Setu" className="w-20 h-20 mb-8 drop-shadow-lg" />
                    <h1 className="text-4xl font-extrabold leading-tight mb-4">
                        Ann Setu
                    </h1>
                    <p className="text-lg text-white/80 leading-relaxed">
                        Smart Cold Storage Management — monitor inventory, loading docks,
                        IoT sensors and billing from one unified dashboard.
                    </p>

                    <div className="mt-10 grid grid-cols-2 gap-4 text-sm text-white/70">
                        {[
                            "Real-time IoT",
                            "Inventory Tracking",
                            "Billing & Reports",
                            "Farmer Management",
                        ].map((f) => (
                            <div key={f} className="flex items-center gap-2">
                                <span className="w-2 h-2 bg-white/60 rounded-full" />
                                {f}
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* Right panel — login form */}
            <div className="flex-1 flex items-center justify-center px-6 py-12 bg-gray-50">
                <div className="w-full max-w-md">
                    {/* Mobile logo */}
                    <div className="flex lg:hidden flex-col items-center mb-8">
                        <img src="/ann-setu-logo.svg" alt="Ann Setu" className="w-14 h-14 mb-2" />
                        <h2 className="text-xl font-bold text-gray-800">Ann Setu</h2>
                    </div>

                    <div className="bg-white rounded-2xl shadow-lg border border-gray-100 p-8 sm:p-10">
                        <h2 className="text-2xl font-bold text-gray-900 mb-1">Welcome back</h2>
                        <p className="text-sm text-gray-500 mb-8">
                            Sign in with your email or mobile number
                        </p>

                        {/* Error banner */}
                        {error && (
                            <div className="flex items-center gap-2 bg-red-50 border border-red-200 text-red-700 text-sm rounded-lg px-4 py-3 mb-5">
                                <AlertCircle size={16} className="shrink-0" />
                                {error}
                            </div>
                        )}

                        <form onSubmit={handleSubmit} className="flex flex-col gap-5">
                            {/* Identifier field (email or phone) */}
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1.5">
                                    Email or Mobile Number
                                </label>
                                <div className="relative">
                                    <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400">
                                        {/^\d/.test(identifier) ? (
                                            <Phone size={18} />
                                        ) : (
                                            <Mail size={18} />
                                        )}
                                    </span>
                                    <input
                                        type="text"
                                        required
                                        value={identifier}
                                        onChange={(e) => setIdentifier(e.target.value)}
                                        placeholder="you@example.com  or  9876543210"
                                        autoComplete="username"
                                        className="w-full pl-11 pr-4 py-3 border border-gray-300 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#33cc33]/40 focus:border-[#33cc33] transition placeholder:text-gray-400"
                                    />
                                </div>
                            </div>

                            {/* Password field */}
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1.5">
                                    Password
                                </label>
                                <div className="relative">
                                    <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400">
                                        <Lock size={18} />
                                    </span>
                                    <input
                                        type={showPassword ? "text" : "password"}
                                        required
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                        placeholder="Enter your password"
                                        autoComplete="current-password"
                                        className="w-full pl-11 pr-11 py-3 border border-gray-300 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#33cc33]/40 focus:border-[#33cc33] transition placeholder:text-gray-400"
                                    />
                                    <button
                                        type="button"
                                        tabIndex={-1}
                                        onClick={() => setShowPassword((v) => !v)}
                                        className="absolute right-3.5 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 transition"
                                    >
                                        {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                                    </button>
                                </div>
                            </div>

                            {/* Remember me + forgot */}
                            <div className="flex items-center justify-between text-sm">
                                <label className="flex items-center gap-2 text-gray-600 cursor-pointer select-none">
                                    <input type="checkbox" className="accent-[#33cc33] w-4 h-4 rounded" />
                                    Remember me
                                </label>
                                <a href="#" className="text-[#33cc33] hover:underline font-medium">
                                    Forgot password?
                                </a>
                            </div>

                            {/* Submit */}
                            <button
                                type="submit"
                                disabled={submitting}
                                className="w-full flex items-center justify-center gap-2 py-3 bg-[#33cc33] text-white font-semibold rounded-xl hover:bg-[#2db82d] active:scale-[0.98] transition-all shadow-md disabled:opacity-70 disabled:cursor-not-allowed"
                            >
                                {submitting ? (
                                    <>
                                        <Loader2 size={18} className="animate-spin" />
                                        Signing in…
                                    </>
                                ) : (
                                    "Sign In"
                                )}
                            </button>
                        </form>

                        {/* Footer help */}
                        <p className="text-center text-sm text-gray-400 mt-8">
                            Don&apos;t have an account?{" "}
                            <a href="#" className="text-[#33cc33] font-medium hover:underline">
                                Contact Admin
                            </a>
                        </p>
                    </div>

                    {/* Dev credentials hint */}
                    <div className="mt-6 bg-amber-50 border border-amber-200 rounded-xl px-5 py-4 text-xs text-amber-800">
                        <p className="font-semibold mb-1.5">🔑 Dev Credentials</p>
                        <div className="grid grid-cols-[auto_1fr_1fr] gap-x-3 gap-y-1">
                            <span className="font-medium">Admin</span>
                            <span>admin@annsetu.com</span>
                            <span>admin123</span>
                            <span className="font-medium">Manager</span>
                            <span>manager@annsetu.com</span>
                            <span>manager123</span>
                            <span className="font-medium">Operator</span>
                            <span>9000000001</span>
                            <span>operator123</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
